class Solution {
    public int kIncreasing(int[] arr, int k) {
        int n = arr.length;
        int res = 0;
        for (int i = k; i < n; i++) {
            if (arr[i - k] > arr[i]) {
                res += arr[i - k] - arr[i];
            }
        }
        return res;
    }
}
